### k6 Load Test Script
```javascript
// e2e/k6/rate-limit-burst.k6.js
import http from "k6/http";
import { check, sleep } from "k6";
import { Counter, Rate, Trend } from "k6/metrics";

// Custom metrics
const successCounter = new Counter("successful_requests");
const deniedCounter = new Counter("rate_limited_requests");
const bypassRate = new Rate("bypass_rate");
const responseTime = new Trend("response_time");

// Test configuration
const RATE_LIMIT = 100;  // Expected limit per window
const BURST_SIZE = 500;  // Total requests to fire
const VUS = 50;          // Concurrent virtual users

export const options = {
  scenarios: {
    // Scenario 1: Pure burst (all at once)
    burst: {
      executor: "shared-iterations",
      vus: VUS,
      iterations: BURST_SIZE,
      maxDuration: "30s",
      env: { SCENARIO: "burst" },
    },
    // Scenario 2: Sustained load
    sustained: {
      executor: "constant-arrival-rate",
      rate: 200,  // 200 requests per second
      timeUnit: "1s",
      duration: "10s",
      preAllocatedVUs: 50,
      startTime: "35s",
      env: { SCENARIO: "sustained" },
    },
  },
  thresholds: {
    // CRITICAL: No more than limit requests should succeed
    successful_requests: [`count<=${RATE_LIMIT + 5}`],  // Small buffer for timing
    // Bypass rate must be near zero
    bypass_rate: ["rate<0.02"],  // <2% bypass acceptable
    // Response time should be reasonable
    response_time: ["p95<500"],  // 95th percentile under 500ms
  },
};

export default function () {
  const scenario = __ENV.SCENARIO || "burst";
  const startTime = Date.now();

  const res = http.get("http://localhost:3000/api/agents", {
    headers: {
      "X-API-Key": "test-api-key",
      "X-Request-ID": `${scenario}-${__VU}-${__ITER}`,
    },
    timeout: "5s",
  });

  const elapsed = Date.now() - startTime;
  responseTime.add(elapsed);

  // Track results
  if (res.status === 200) {
    successCounter.add(1);
    // After RATE_LIMIT, any 200 is a bypass
    if (successCounter.value > RATE_LIMIT) {
      bypassRate.add(1);
      console.log(`[k6] BYPASS DETECTED: Request ${__ITER} got 200 (total success: ${successCounter.value})`);
    } else {
      bypassRate.add(0);
    }
  } else if (res.status === 429) {
    deniedCounter.add(1);
    bypassRate.add(0);

    // Verify rate limit headers
    check(res, {
      "has X-RateLimit-Limit header": (r) => r.headers["X-Ratelimit-Limit"] !== undefined,
      "has X-RateLimit-Remaining header": (r) => r.headers["X-Ratelimit-Remaining"] !== undefined,
      "has Retry-After header": (r) => r.headers["Retry-After"] !== undefined,
    });
  } else {
    console.log(`[k6] Unexpected status: ${res.status}`);
  }

  check(res, {
    "status is 200 or 429": (r) => r.status === 200 || r.status === 429,
  });
}

export function handleSummary(data) {
  const successful = data.metrics.successful_requests?.values?.count || 0;
  const denied = data.metrics.rate_limited_requests?.values?.count || 0;
  const bypass = data.metrics.bypass_rate?.values?.rate || 0;

  console.log("\n========================================");
  console.log("       RATE LIMIT BURST TEST RESULTS     ");
  console.log("========================================");
  console.log(`Total requests:        ${successful + denied}`);
  console.log(`Successful (200):      ${successful}`);
  console.log(`Rate limited (429):    ${denied}`);
  console.log(`Bypass rate:           ${(bypass * 100).toFixed(2)}%`);
  console.log(`Expected limit:        ${RATE_LIMIT}`);
  console.log("----------------------------------------");

  if (successful <= RATE_LIMIT + 5 && bypass < 0.02) {
    console.log("RESULT: PASS ✓");
    console.log("Rate limiter held under burst load");
  } else {
    console.log("RESULT: FAIL ✗");
    console.log(`Bypass detected! ${successful} > ${RATE_LIMIT}`);
  }
  console.log("========================================\n");

  return {
    "stdout": JSON.stringify({
      successful,
      denied,
      bypass_rate: bypass,
      passed: successful <= RATE_LIMIT + 5,
    }, null, 2),
    "e2e-results/rate-limit-burst.json": JSON.stringify(data, null, 2),
  };
}
