### Jest E2E Test Wrapper
```typescript
// e2e/rate-limit-burst.e2e.test.ts
import { exec } from "child_process";
import { promisify } from "util";
import { startTestGateway, stopTestGateway } from "./utils/gateway";

const execAsync = promisify(exec);

describe("E2E: Rate Limiter Burst Prevention", () => {
  let gateway: TestGateway;

  beforeAll(async () => {
    console.log("[E2E] Starting test gateway...");
    gateway = await startTestGateway({
      rateLimit: { limit: 100, windowMs: 60000 },
    });
    console.log(`[E2E] Gateway started on port ${gateway.port}`);
  }, 30000);

  afterAll(async () => {
    console.log("[E2E] Stopping gateway...");
    await stopTestGateway(gateway);
  });

  it("should prevent rate limit bypass under burst load", async () => {
    console.log("[E2E] Running k6 burst test...");

    const { stdout, stderr } = await execAsync(
      `k6 run --env BASE_URL=${gateway.url} e2e/k6/rate-limit-burst.k6.js`,
      { timeout: 120000 }
    );

    console.log("[E2E] k6 output:", stdout);
    if (stderr) console.error("[E2E] k6 stderr:", stderr);

    // Parse results
    const results = JSON.parse(stdout);

    expect(results.passed).toBe(true);
    expect(results.successful).toBeLessThanOrEqual(105);  // limit + buffer
    expect(results.bypass_rate).toBeLessThan(0.02);

    console.log(`[E2E] PASS: ${results.successful} requests allowed (limit: 100)`);
  }, 180000);

  it("should return correct rate limit headers", async () => {
    // Make a single request to verify headers
    const response = await fetch(`${gateway.url}/api/agents`, {
      headers: { "X-API-Key": "header-test-key" },
    });

    expect(response.headers.get("X-RateLimit-Limit")).toBe("100");
    expect(response.headers.get("X-RateLimit-Remaining")).toBeDefined();
    expect(response.headers.get("X-RateLimit-Reset")).toBeDefined();

    const remaining = parseInt(response.headers.get("X-RateLimit-Remaining") || "0");
    console.log(`[E2E] Rate limit headers: limit=100, remaining=${remaining}`);
  });

  it("should include Retry-After header when rate limited", async () => {
    // Exhaust the limit for a specific key
    const testKey = `retry-test-${Date.now()}`;

    // Make 100 requests
    for (let i = 0; i < 100; i++) {
      await fetch(`${gateway.url}/api/agents`, {
        headers: { "X-API-Key": testKey },
      });
    }

    // Next request should be rate limited
    const response = await fetch(`${gateway.url}/api/agents`, {
      headers: { "X-API-Key": testKey },
    });

    expect(response.status).toBe(429);
    expect(response.headers.get("Retry-After")).toBeDefined();

    const retryAfter = parseInt(response.headers.get("Retry-After") || "0");
    console.log(`[E2E] 429 response with Retry-After: ${retryAfter}s`);
    expect(retryAfter).toBeGreaterThan(0);
    expect(retryAfter).toBeLessThanOrEqual(60);
  });
});
