```bash
#!/bin/bash
# e2e/scripts/rate-limit-autocannon.sh

set -e

BASE_URL="${BASE_URL:-http://localhost:3000}"
RATE_LIMIT=100
CONNECTIONS=50
DURATION=5

echo "========================================="
echo "Rate Limit Burst Test (autocannon)"
echo "========================================="
echo "Target: ${BASE_URL}/api/agents"
echo "Expected limit: ${RATE_LIMIT}"
echo "Connections: ${CONNECTIONS}"
echo "Duration: ${DURATION}s"
echo "-----------------------------------------"

# Run burst test
RESULT=$(autocannon -c $CONNECTIONS -d $DURATION \
  -H "X-API-Key: burst-test" \
  --json "${BASE_URL}/api/agents")

# Parse results
TOTAL=$(echo $RESULT | jq .requests.total)
SUCCESS_2XX=$(echo $RESULT | jq .2xx)
RATE_LIMITED_429=$(echo $RESULT | jq .429 2>/dev/null || echo 0)

echo ""
echo "Results:"
echo "  Total requests:    $TOTAL"
echo "  Successful (2xx):  $SUCCESS_2XX"
echo "  Rate limited:      $RATE_LIMITED_429"

if [ "$SUCCESS_2XX" -le "$((RATE_LIMIT + 10))" ]; then
  echo ""
  echo "RESULT: PASS ✓"
  echo "Rate limiter held! ($SUCCESS_2XX <= $RATE_LIMIT)"
  exit 0
else
  echo ""
  echo "RESULT: FAIL ✗"
  echo "Rate limit bypassed! ($SUCCESS_2XX > $RATE_LIMIT)"
  exit 1
fi
